TEXT:
Message catalog validation: {status}
  messages: {message_count}
  text rows: {text_row_count}
  locales: {locales}
  issues: {issue_count}
  boundary: report-only; no DBF, HELP DATA, CMDHELPCHK, source-mining, or catalog mutation.

Message catalog provider status:
  mode: {mode}
  active catalog present: {present}
  active catalog loaded: {loaded}
  message count: {message_count}
  text row count: {text_row_count}
  active dbf dir: {dbf_dir}
  active indexes dir: {indexes_dir}
  active lmdb dir: {lmdb_dir}
  detail: {detail}
  boundary: read-only status/load; no DBF/CDX/LMDB mutation; no runtime writeback

SET LANGUAGE active message emission:
  current locale: {locale}
  provider mode: {mode}
  active catalog loaded: {loaded}
  symbol: HELP_HINT_COMMAND
  fallback locale: en-US
  text: {text}
  boundary: read-only emission; no DBF/CDX/LMDB mutation; no runtime writeback

SET LANGUAGE active catalog check:
  current language: {locale}
  message catalog mode: {mode}
  active catalog present: {present}
  active catalog loaded: {loaded}
  message count: {message_count}
  text row count: {text_row_count}
  lookup symbol: MESSAGE_LOCALE_SET
  lookup locale: {locale}
  lookup text: {text}
  runtime active catalog lookup proof: {proof}
  boundary: read-only lookup; no DBF/CDX/LMDB mutation; no runtime writeback

SET MESSAGE EMIT:
  current locale: {current_locale}
  provider mode: {mode}
  active catalog present: {present}
  active catalog loaded: {loaded}
  message count: {message_count}
  text row count: {text_row_count}
  symbol: {symbol}
  locale: {locale}
  placeholder arg supplied: {placeholder_arg}
  placeholder substitution proof: {substituted}
  text: {text}
  runtime controlled emission proof: {proof}
  boundary: explicit diagnostic emission; no DBF/CDX/LMDB mutation; no runtime writeback

Message catalog report: report-only
  schema intent: SYSTEM_MESSAGES + SYSTEM_MESSAGE_TEXT
  messages: {message_count}
  text rows: {text_row_count}
  locales: {locales}
  validation issues: {issue_count}
  boundary: report-only console report; no DBF, HELP DATA, CMDHELPCHK, source-mining, file, or catalog mutation.
